/** UsptEvlOnlineDao.updateCharmnAllfalse */
update uspt_evl_mfcmm
   set charmn = false
 where evl_cmit_id = #{evlCmitId}

/** UsptEvlOnlineDao.updateCharmn */
update uspt_evl_mfcmm
  set charmn = true
    , updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where evl_mfcmm_id = #{evlMfcmmId}

/** UsptEvlOnlineDao.updateAttend */
update uspt_evl_mfcmm
  set atend_sttus_cd = #{atendSttusCd}
    , updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where evl_mfcmm_id = #{evlMfcmmId}

/** UsptEvlOnlineDao.updateEvas */
update uspt_evl_mfcmm
  set evas_resn_cn = #{evasResnCn}

    , atend_sttus_cd = #{atendSttusCd}

    , updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where evl_mfcmm_id = #{evlMfcmmId}

mapper.select:
/** UsptEvlOnlineDao.selectValidKeyByAddAllot */
select count(evl_iem_result_adsbtr_id) as cnt
  from USPT_EVL_IEM_RESULT_ADSBTR
 where evl_iem_result_adsbtr_id = #{evlIemResultAdsbtrId}

mapper.update:
		with update_data as (
        	 update uspt_evl_iem_result_adsbtr set
	      	 		      evl_score                 = #{evlScore}
	      	 		    , evl_cn					= #{evlCn}
						, adsbtr_resn_cn            = #{adsbtrResnCn}
						, updater_id                = #{updaterId}
						, updated_dt                = #{updatedDt}
				where evl_iem_result_adsbtr_id = #{evlIemResultAdsbtrId}
				returning *
			)
	         insert into uspt_evl_iem_result_adsbtr (
												     evl_iem_result_adsbtr_id
												   , evl_iem_id
												   , evl_trget_id
												   , evl_cmit_id
											   	   , evl_score
												   , evl_cn
												   , adsbtr_resn_cn
												   , creator_id
												   , created_dt
												    )
										      select #{evlIemResultAdsbtrId}
												   , #{evlIemId}
												   , #{evlTrgetId}
												   , #{evlCmitId}
												   , #{evlScore}
												   , #{evlCn}
												   , #{adsbtrResnCn}
												   , #{creatorId}
												   , #{createdDt}
				where not exists (select * from update_data)
